import React from 'react';

function Services() {
  return (
    <div className="container py-5">
      <h2 className="text-center fw-bold mb-5">माझ्या सर्व्हिसेस</h2>
      <div className="row g-4 text-center">
        <div className="col-md-4">
          <div className="card h-100 shadow-sm p-4">
            <h4>Web Dev</h4>
            <p>React & Bootstrap आधारित वेबसाईट्स.</p>
          </div>
        </div>
        {/* असे अजून कार्ड्स तुम्ही जोडू शकता */}
      </div>
    </div>
  );
}
export default Services;
